<!doctype html><html><body style="font-family: sans-serif"><h1>Invoice {{ $invoice->invoice_number }}</h1><p>Order: {{ $invoice->order->order_number }}</p><p>Customer: {{ $invoice->order->customer->name }}</p><table width="100%" border="1" cellspacing="0" cellpadding="6"><tr><th>Description</th><th>Qty</th><th>Total</th></tr>@foreach($invoice->order->quote->items as $item)<tr><td>{{ $item->description }}</td><td>{{ $item->quantity }}</td><td>{{ $invoice->currency }} {{ number_format($item->total_price,2) }}</td></tr>@endforeach</table><h2>Total: {{ $invoice->currency }} {{ number_format($invoice->amount,2) }}</h2></body></html>
